'use client';

import { useSearchParams } from 'next/navigation';
import React, { useEffect, useState } from 'react';
import Navbar from '../components/Navbar';

export default function Page() {
    const searchParams = useSearchParams();
    const query = searchParams.get('query')?.toLowerCase() || '';

    const [hotels, setHotels] = useState([]);
    const [filteredHotels, setFilteredHotels] = useState([]);

    useEffect(() => {
        const fetchHotels = async () => {
            try {
                const res = await fetch('http://localhost:5000/api/hotels');
                const data = await res.json();
                setHotels(data);
            } catch (error) {
                console.error('Error fetching hotels:', error);
            }
        };

        fetchHotels();
    }, []);

    useEffect(() => {
        if (!query) return;
        const results = hotels.filter(hotel =>
            (hotel.name && hotel.name.toLowerCase().includes(query)) ||
            (hotel.location && hotel.location.toLowerCase().includes(query))
        );
        setFilteredHotels(results);
    }, [query, hotels]);

    return (
        <>
            <Navbar />
            <div style={{ padding: '1rem' }}>
                <h2>Search Results for: <em>{query}</em></h2>

                {filteredHotels.length > 0 ? (
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(330px, 1fr))', gap: '5rem', margin: '3rem 1rem'}}>
                        {filteredHotels.map(hotel => (
                            <div key={hotel._id} style={{ border: '1px solid #eee', borderRadius: '8px', padding: '1rem' }}>
                                <img
                                    src={hotel.thumbnailImage || '/hotel_placeholder.png'}
                                    alt={hotel.name}
                                    style={{ width: '50%', height: '400px', objectFit: 'cover', borderRadius: '8px' }}
                                />
                                <h3>{hotel.name}</h3>
                                <p>{hotel.location}</p>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p>No hotels found.</p>
                )}
            </div>
        </>
    );
}
